class RateLimiter:
    """Prevents UDP amplification abuse by rate-limiting responses per IP."""

    def __init__(self, max_requests_per_second: int = 5, window_seconds: int = 10):
        self.max_requests = max_requests_per_second * window_seconds
        self.window_seconds = window_seconds
        self.requests: Dict[str, List[float]] = defaultdict(list)
        self._lock = threading.Lock()

    def is_allowed(self, ip: str) -> bool:
        now = time.time()
        with self._lock:
            # Clean old entries
            self.requests[ip] = [
                t for t in self.requests[ip]
                if now - t < self.window_seconds
            ]
            if len(self.requests[ip]) >= self.max_requests:
                return False
            self.requests[ip].append(now)
            return True

    def cleanup(self):
        """Remove stale entries periodically."""
        now = time.time()
        with self._lock:
            stale_ips = [
                ip for ip, times in self.requests.items()
                if not times or now - times[-1] > self.window_seconds * 2
            ]
            for ip in stale_ips:
                del self.requests[ip]


class GameServer:
    # Protocol constants
    MAGIC_HEADER = b'\xFF\xFF\xFF\xFF'
    QUERY_STATUS = b'getstatus'
    QUERY_INFO = b'getinfo'
    QUERY_CHALLENGE = b'getchallenge'

    # Maximum response size to limit amplification factor
    MAX_RESPONSE_SIZE = 4096

    def __init__(self, host: str = "0.0.0.0", port: int = 27015,
                 rate_limit_rps: int = 5):
        self.host = host
        self.port = port
        self.sock: Optional[socket.socket] = None
        self.running = False
        self.game_state = GameState()
        self.players: Dict[str, Player] = {}
        self._players_lock = threading.Lock()
        self.rate_limiter = RateLimiter(max_requests_per_second=rate_limit_rps)
        self.start_time = time.time()

        # Challenge-response system to mitigate spoofed source IPs
        self._challenges: Dict[str, tuple] = {}  # ip -> (challenge, timestamp)
        self._challenge_lock = threading.Lock()
        self._challenge_timeout = 30  # seconds

    def add_player(self, name: str, team: str = "", score: int = 0, ping: int = 50):
        with self._players_lock:
            self.players[name] = Player(name=name, score=score, ping=ping, team=team)
        logger.info(f"Player '{name}' joined the server.")

    def remove_player(self, name: str):
        with self._players_lock:
            if name in self.players:
                del self.players[name]
                logger.info(f"Player '{name}' left the server.")

    def update_player(self, name: str, score: int = None, ping: int = None, team: str = None):
        with self._players_lock:
            if name in self.players:
                if score is not None:
                    self.players[name].score = score
                if ping is not None:
                    self.players[name].ping = ping
                if team is not None:
                    self.players[name].team = team

    def _generate_challenge(self, addr: tuple) -> str:
        """Generate a challenge token for an address to verify it's not spoofed."""
        ip_str = f"{addr[0]}:{addr[1]}"
        challenge = hashlib.sha256(
            f"{ip_str}{time.time()}{id(self)}".encode()
        ).hexdigest()[:16]
        with self._challenge_lock:
            self._challenges[ip_str] = (challenge, time.time())
        return challenge

    def _verify_challenge(self, addr: tuple, challenge: str) -> bool:
        """Verify a challenge token from a client."""
        ip_str = f"{addr[0]}:{addr[1]}"
        with self._challenge_lock:
            if ip_str not in self._challenges:
                return False
            stored_challenge, timestamp = self._challenges[ip_str]
            if time.time() - timestamp > self._challenge_timeout:
                del self._challenges[ip_str]
                return False
            if stored_challenge == challenge:
                del self._challenges[ip_str]
                return True
        return False

    def _cleanup_challenges(self):
        """Remove expired challenges."""
        now = time.time()
        with self._challenge_lock:
            expired = [
                k for k, (_, ts) in self._challenges.items()
                if now - ts > self._challenge_timeout
            ]
            for k in expired:
                del self._challenges[k]

    def _build_info_response(self) -> bytes:
        """Build a compact server info response (no player details)."""
        with self._players_lock:
            player_count = len(self.players)

        info = {
            "server_name": self.game_state.server_name,
            "map": self.game_state.map_name,
            "game_mode": self.game_state.game_mode,
            "players": player_count,
            "max_players": self.game_state.max_players,
            "version": self.game_state.server_version,
            "password": self.game_state.password_protected,
            "uptime": int(time.time() - self.start_time),
        }
        payload = json.dumps(info, separators=(',', ':')).encode('utf-8')
        return self.MAGIC_HEADER + b'infoResponse\n' + payload

    def _build_status_response(self) -> bytes:
        """Build full status response with player list and game state."""
        with self._players_lock:
            players_data = [p.to_dict() for p in self.players.values()]

        status = {
            "server_name": self.game_state.server_name,
            "map": self.game_state.map_name,
            "game_mode": self.game_state.game_mode,
            "players": len(players_data),
            "max_players": self.game_state.max_players,
            "version": self.game_state.server_version,
            "password": self.game_state.password_protected,
            "round": self.game_state.round_number,
            "time_remaining": self.game_state.time_remaining,
            "score_limit": self.game_state.score_limit,
            "uptime": int(time.time() - self.start_time),
            "player_list": players_data,
        }

        payload = json.dumps(status, separators=(',', ':')).encode('utf-8')

        # Truncate player list if response is too large to limit amplification
        while len(payload) > self.MAX_RESPONSE_SIZE - 20 and players_data:
            players_data.pop()
            status["player_list"] = players_data
            status["player_list_truncated"] = True
            payload = json.dumps(status, separators=(',', ':')).encode('utf-8')

        return self.MAGIC_HEADER + b'statusResponse\n' + payload

    def _build_challenge_response(self, challenge: str) -> bytes:
        """Build challenge response - small packet."""
        return self.MAGIC_HEADER + b'challengeResponse\n' + challenge.encode('utf-8')

    def _handle_query(self, data: bytes, addr: tuple):
        """Handle an incoming query packet."""
        ip = addr[0]

        # Rate limiting
        if not self.rate_limiter.is_allowed(ip):
            logger.warning(f"Rate limited: {ip}")
            return

        # Validate magic header
        if not data.startswith(self.MAGIC_HEADER):
            return

        payload = data[len(self.MAGIC_HEADER):]

        # Handle different query types
        if payload.startswith(self.QUERY_CHALLENGE):
            # Challenge request - always respond (small response)
            challenge = self._generate_challenge(addr)
            response = self._build_challenge_response(challenge)
            self.sock.sendto(response, addr)
            logger.debug(f"Sent challenge to {addr}")

        elif payload.startswith(self.QUERY_INFO):
            # Basic info - small response, allowed without challenge
            response = self._build_info_response()
            self.sock.sendto(response, addr)
            logger.debug(f"Sent info to {addr}")

        elif payload.startswith(self.QUERY_STATUS):
            # Full status - larger response, requires valid challenge
            # Extract challenge token from query
            parts = payload.split(b' ', 1)
            if len(parts) < 2:
                # No challenge provided - send back a challenge requirement
                challenge = self._generate_challenge(addr)
                error_resp = self.MAGIC_HEADER + b'needChallenge\n' + challenge.encode('utf-8')
                self.sock.sendto(error_resp, addr)
                logger.debug(f"Requested challenge from {addr} for status query")
                return

            challenge_token = parts[1].decode('utf-8', errors='ignore').strip()
            if not self._verify_challenge(addr, challenge_token):
                logger.warning(f"Invalid challenge from {addr}")
                return

            response = self._build_status_response()
            self.sock.sendto(response, addr)
            logger.debug(f"Sent status to {addr} ({len(response)} bytes)")

        else:
            logger.debug(f"Unknown query from {addr}: {payload[:50]}")

    def _cleanup_loop(self):
        """Periodic cleanup of rate limiter and challenges."""
        while self.running:
            time.sleep(30)
            self.rate_limiter.cleanup()
            self._cleanup_challenges()

    def _game_simulation_loop(self):
        """Simulate game state changes for demonstration."""
        while self.running:
            time.sleep(1)
            if self.game_state.time_remaining > 0:
                self.game_state.time_remaining -= 1
            else:
                self.game_state.time_remaining = self.game_state.time_limit
                self.game_state.round_number += 1
                self.game_state.map_name = f"dm_map_{self.game_state.round_number % 5}"

            # Simulate score updates
            with self._players_lock:
                import random
                for player in self.players.values():
                    if random.random() < 0.1:
                        player.score += random.randint(1, 3)
                    player.ping = max(10, player.ping + random.randint(-5, 5))

    def start(self):
        """Start the game server query handler."""
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.sock.settimeout(1.0)
        self.sock.bind((self.host, self.port))
        self.running = True

        logger.info(f"Game server listening on {self.host}:{self.port}")
        logger.info(f"Max response size: {self.MAX_RESPONSE_SIZE} bytes")
        logger.info("Challenge-response required for full status queries")

        # Start cleanup thread
        cleanup_thread = threading.Thread(target=self._cleanup_loop, daemon=True)
        cleanup_thread.start()

        # Start game simulation
        sim_thread = threading.Thread(target=self._game_simulation_loop, daemon=True)
        sim_thread.start()

        try:
            while self.running:
                try:
                    data, addr = self.sock.recvfrom(1024)
                    if data:
                        self._handle_query(data, addr)
                except socket.timeout:
                    continue
                except OSError:
                    if self.running:
                        raise
        except KeyboardInterrupt:
            logger.info("Server shutting down...")
        finally:
            self.stop()

    def stop(self):
        self.running = False
        if self.sock:
            self.sock.close()
            self.sock = None
        logger.info("Server stopped.")


class GameServerBrowserClient:
    """Client for querying the game server - for testing purposes."""

    MAGIC_HEADER = b'\xFF\xFF\xFF\xFF'

    def __init__(self, timeout: float = 5.0):
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.settimeout(timeout)

    def get_info(self, host: str, port: int) -> Optional[dict]:
        """Get basic server info (no challenge needed)."""
        query = self.MAGIC_HEADER + b'getinfo'
        self.sock.sendto(query, (host, port))
        try:
            data, _ = self.sock.recvfrom(4096)
            if data.startswith(self.MAGIC_HEADER + b'infoResponse\n'):
                payload = data[len(self.MAGIC_HEADER) + len(b'infoResponse\n'):]
                return json.loads(payload.decode('utf-8'))
        except socket.timeout:
            logger.error("Timeout waiting for info response")
        return None

    def get_status(self, host: str, port: int) -> Optional[dict]:
        """Get full server status using challenge-response protocol."""
        # Step 1: Request a challenge
        challenge_query = self.MAGIC_HEADER + b'getchallenge'
        self.sock.sendto(challenge_query, (host, port))

        try:
            data, _ = self.sock.recvfrom(4096)
        except socket.timeout:
            logger.error("Timeout waiting for challenge")
            return None

        # Parse challenge
        challenge_prefix = self.MAGIC_HEADER + b'challengeResponse\n'
        need_challenge_prefix = self.MAGIC_HEADER + b'needChallenge\n'

        challenge = None
        if data.startswith(challenge_prefix):
            challenge = data[len(challenge_prefix):].decode('utf-8').strip()
        else:
            logger.error("Unexpected response to challenge request")
            return None

        # Step 2: Send status query with challenge
        status_query = self.MAGIC_HEADER + b'getstatus ' + challenge.encode('utf-8')
        self.sock.sendto(status_query, (host, port))

        try:
            data, _ = self.sock.recvfrom(8192)
        except socket.timeout:
            logger.error("Timeout waiting for status response")
            return None

        status_prefix = self.MAGIC_HEADER + b'statusResponse\n'
        if data.startswith(status_prefix):
            payload = data[len(status_prefix):]
            return json.loads(payload.decode('utf-8'))

        logger.error("Unexpected status response")
        return None

    def close(self):
        self.sock.close()


